// biome-ignore-all lint/a11y/noSvgWithoutTitle: Icons are decorative by default and accept a title prop when a label is needed.
// biome-ignore-all lint/security/noDangerouslySetInnerHtml: The SVG paths are static local icon data copied into the docs app.

import { cn } from "@zeron-ui/ui/utils";
import * as React from "react";

export type AiStudioIconProps = Omit<
  React.ComponentPropsWithoutRef<"svg">,
  "children"
> & {
  size?: number | string;
  title?: string;
};

type IconPart = {
  transform: string;
  markup: string;
};

function createAiStudioIcon(name: string, parts: IconPart[]) {
  const Component = React.forwardRef<SVGSVGElement, AiStudioIconProps>(
    ({ className, size = 20, title, ...props }, ref) => (
      <svg
        ref={ref}
        width={size}
        height={size}
        viewBox="0 0 20 20"
        fill="none"
        xmlns="http://www.w3.org/2000/svg"
        className={cn("shrink-0", className)}
        role={title ? "img" : undefined}
        aria-hidden={title ? undefined : true}
        {...props}
      >
        {title ? <title>{title}</title> : null}
        {parts.map((part) => (
          <g
            key={`${part.transform}-${part.markup}`}
            transform={part.transform}
            dangerouslySetInnerHTML={{ __html: part.markup }}
          />
        ))}
      </svg>
    ),
  );

  Component.displayName = name;

  return Component;
}

